## Chart
chart_spec: ```
```yaml
chart_config:
  title: "2025 Annual Sales Analysis Dashboard"
  description: "Comprehensive visualization of financial performance, operational efficiency, and strategic insights"
  layout: "dashboard"

  charts:
    # Row 1: Key Metrics Overview
    - type: "metric_cards"
      position: { row: 1, cols: 4 }
      data:
        - label: "Total Revenue"
          value: "$208.3M"
          trend: "+36%"
          trend_direction: "up"
        - label: "Total Profit"
          value: "$45.0M"
          trend: "21.6% margin"
          trend_direction: "neutral"
        - label: "Total Expenses"
          value: "$163.3M"
          trend: "+16%"
          trend_direction: "up"
        - label: "Headcount"
          value: "289"
          trend: "+23%"
          trend_direction: "up"

    # Row 2: Quarterly Performance
    - type: "combo_chart"
      position: { row: 2, col: 1, width: 2 }
      title: "Quarterly Revenue & Profit Trends"
      x_axis: "Quarter"
      y_axes:
        primary:
          label: "Revenue ($M)"
          series:
            - name: "Revenue"
              type: "bar"
              color: "#4A90E2"
        secondary:
          label: "Profit ($M)"
          series:
            - name: "Profit"
              type: "line"
              color: "#50C878"
              marker: true
      data:
        - { quarter: "Q1", revenue: 45.2, profit: 7.2 }
        - { quarter: "Q2", revenue: 49.8, profit: 10.1 }
        - { quarter: "Q3", revenue: 51.9, profit: 10.5 }
        - { quarter: "Q4", revenue: 61.4, profit: 17.2 }
      annotations:
        - { quarter: "Q4", text: "Strongest Quarter", position: "top" }
        - { quarter: "Q3", text: "Slight Dip", position: "bottom" }

    - type: "line_chart"
      position: { row: 2, col: 3, width: 2 }
      title: "Profit Margin by Quarter (%)"
      x_axis: "Quarter"
      y_axis: 
        label: "Profit Margin (%)"
        min: 0
        max: 30
      series:
        - name: "Profit Margin"
          color: "#F5A623"
          marker_size: 8
      data:
        - { quarter: "Q1", margin: 16 }
        - { quarter: "Q2", margin: 20 }
        - { quarter: "Q3", margin: 20 }
        - { quarter: "Q4", margin: 28 }
      reference_line:
        value: 21.6
        label: "Annual Average"
        style: "dashed"

    # Row 3: Operational Efficiency
    - type: "grouped_bar_chart"
      position: { row: 3, col: 1, width: 2 }
      title: "Revenue vs Expenses Growth (Q1→Q4)"
      x_axis: "Metric"
      y_axis: "Growth Rate (%)"
      series:
        - name: "Growth Rate"
          colors: ["#50C878", "#E74C3C"]
      data:
        - { metric: "Revenue", growth: 36 }
        - { metric: "Expenses", growth: 16 }
      annotations:
        - text: "2.25x better revenue growth"
          position: "top_center"

    - type: "combo_chart"
      position: { row: 3, col: 3, width: 2 }
      title: "Workforce Efficiency"
      x_axis: "Quarter"
      y_axes:
        primary:
          label: "Revenue per Employee ($K)"
          series:
            - name: "Revenue/Employee"
              type: "line"
              color: "#9B59B6"
              marker: true
        secondary:
          label: "Headcount"
          series:
            - name: "Employees"
              type: "bar"
              color: "#BDC3C7"
              opacity: 0.6
      data:
        - { quarter: "Q1", rev_per_emp: 193, employees: 234 }
        - { quarter: "Q2", rev_per_emp: 198, employees: 251 }
        - { quarter: "Q3", rev_per_emp: 195, employees: 266 }
        - { quarter: "Q4", rev_per_emp: 212, employees: 289 }

    # Row 4: Product & Market Analysis
    - type: "horizontal_bar_chart"
      position: { row: 4, col: 1, width: 2 }
      title: "Top 10 Products by Revenue ($M)"
      x_axis: "Revenue ($M)"
      y_axis: "Product"
      series:
        - name: "Revenue"
          color_scale: ["#E74C3C", "#F39C12", "#3498DB"]
      data:
        - { product: "CloudSync Pro", revenue: 42, highlight: true }
        - { product: "DataGuard Enterprise", revenue: 28 }
        - { product: "AI Analytics Suite", revenue: 21 }
        - { product: "SecureVault Plus", revenue: 18 }
        - { product: "WorkFlow Automation", revenue: 15 }
        - { product: "Mobile Connect", revenue: 13 }
        - { product: "API Gateway Pro", revenue: 11 }
        - { product: "DevOps Toolkit", revenue: 9 }
        - { product: "Customer Insights", revenue: 8 }
        - { product: "Integration Hub", revenue: 7 }
      annotations:
        - { product: "CloudSync Pro", text: "20% of total", position: "right" }
        - { bracket: ["CloudSync Pro", "DataGuard Enterprise", "AI Analytics Suite"], 
            text: "Top 3: 44% of revenue", position: "right" }

    - type: "donut_chart"
      position: { row: 4, col: 3, width: 2 }
      title: "Revenue by Geographic Region"
      series:
        - name: "Region Share"
      data:
        - { region: "North America", value: 52, color: "#E74C3C" }
        - { region: "Europe", value: 25, color: "#3498DB" }
        - { region: "Asia-Pacific", value: 15, color: "#F39C12" }
        - { region: "Latin America", value: 5, color: "#9B59B6" }
        - { region: "Middle East & Africa", value: 3, color: "#1ABC9C" }
      center_text:
        primary: "$208.3M"
        secondary: "Total Revenue"
      callouts:
        - { region: "North America", text: "⚠️ High concentration risk" }
        - { region: "Asia-Pacific", text: "📈 Growth opportunity" }

    # Row 5: Strategic Insights
    - type: "waterfall_chart"
      position: { row: 5, col: 1, width: 2 }
      title: "Revenue to Profit Bridge ($M)"
      x_axis: "Component"
      y_axis: "Amount ($M)"
      data:
        - { label: "Total Revenue", value: 208.3, type: "total", color: "#4A90E2" }
        - { label: "Operating Expenses", value: -120.0, type: "decrease", color: "#E74C3C" }
        - { label: "Cost of Goods Sold", value: -43.3, type: "decrease", color: "#E67E22" }
        - { label: "Net Profit", value: 45.0, type: "total", color: "#50C878" }
      annotations:
        - { label: "Net Profit", text: "21.6% margin", position: "top" }

    - type: "alert_panel"
      position: { row: 5, col: 3, width: 2 }
      title: "Strategic Recommendations"
      items:
        - priority: "high"
          icon: "⚠️"
          text: "Diversify beyond CloudSync Pro (20% revenue concentration)"
          action: "Review product portfolio strategy"
        - priority: "high"
          icon: "🌏"
          text: "Expand Asia-Pacific presence (only 15% of revenue)"
          action: "Develop regional growth plan"
        - priority: "medium"
          icon: "🔍"
          text: "Investigate Q3 performance dip"
          action: "Analyze seasonal patterns"
        - priority: "low"
          icon: "✅"
          text: "Maintain expense discipline (16% growth vs 36% revenue)"
          action: "Continue current practices"

  styling:
    theme: "professional"
    color_palette: "corporate_blue"
    font_family: "Inter, sans-serif"
    background: "#FFFFFF"
    grid_color: "#E5E5E5"

  interactivity:
    enable_tooltips: true
    enable_drill_down: true
    enable_filters: ["quarter", "region", "product"]
    enable_export: true

  responsive:
    mobile_layout: "stacked"
    tablet_layout: "2_column"
    desktop_layout: "4_column"
```

This chart specification creates a comprehensive dashboard that:

1. **Highlights key metrics** with prominent metric cards
2. **Shows quarterly trends** with combo charts for revenue, profit, and margins
3. **Demonstrates operational efficiency** through growth comparisons and workforce metrics
4. **Visualizes product concentration** with ranked bar charts and annotations
5. **Displays geographic distribution** with a donut chart highlighting risks and opportunities
6. **Provides strategic context** with waterfall analysis and actionable recommendations

The dashboard uses visual hierarchy, color coding, and annotations to guide viewers through the insights effectively.
```
